Here is a clean, fresh implementation of what the obfuscated code does.

It is essentially an **A\* pathfinding algorithm** on a randomly generated grid with:

- configurable grid size
- blocked/open cells
- 8-direction movement
- straight and diagonal move costs
- either **Manhattan** or **Euclidean** heuristic
- a maximum iteration cap
- start at `(0, 0)`
- goal at `(width - 1, height - 1)`

```javascript
const gridWidth = 20;
const gridHeight = 15;

const config = {
  heuristic: "manhattan",   // "manhattan" or "euclidean"
  diagonalCost: 1.414,
  straightCost: 1,
  maxIterations: 1000,
  obstacleChance: 0.25
};

// 0 = walkable, 1 = blocked
function createRandomGrid(width, height, obstacleChance) {
  const grid = [];

  for (let y = 0; y < height; y++) {
    const row = [];
    for (let x = 0; x < width; x++) {
      row.push(Math.random() < obstacleChance ? 1 : 0);
    }
    grid.push(row);
  }

  return grid;
}

const grid = createRandomGrid(gridWidth, gridHeight, config.obstacleChance);

const start = { x: 0, y: 0 };
const goal = { x: gridWidth - 1, y: gridHeight - 1 };

// Ensure start and goal are walkable
grid[start.y][start.x] = 0;
grid[goal.y][goal.x] = 0;

function heuristicDistance(a, b) {
  const dx = Math.abs(a.x - b.x);
  const dy = Math.abs(a.y - b.y);

  if (config.heuristic === "manhattan") {
    return dx + dy;
  }

  return Math.sqrt(dx * dx + dy * dy);
}

function toKey(node) {
  return `${node.x},${node.y}`;
}

function getWalkableNeighbors(node, grid) {
  const directions = [
    { dx:  0, dy: -1, cost: config.straightCost },
    { dx:  0, dy:  1, cost: config.straightCost },
    { dx: -1, dy:  0, cost: config.straightCost },
    { dx:  1, dy:  0, cost: config.straightCost },
    { dx: -1, dy: -1, cost: config.diagonalCost },
    { dx:  1, dy: -1, cost: config.diagonalCost },
    { dx: -1, dy:  1, cost: config.diagonalCost },
    { dx:  1, dy:  1, cost: config.diagonalCost }
  ];

  const neighbors = [];

  for (const dir of directions) {
    const x = node.x + dir.dx;
    const y = node.y + dir.dy;

    const inBounds =
      x >= 0 &&
      x < gridWidth &&
      y >= 0 &&
      y < gridHeight;

    if (!inBounds) continue;
    if (grid[y][x] !== 0) continue;

    neighbors.push({
      x,
      y,
      moveCost: dir.cost
    });
  }

  return neighbors;
}

function reconstructPath(cameFrom, closedSet, openSet, endKey) {
  const path = [];
  let currentKey = endKey;

  while (currentKey) {
    const node =
      openSet[currentKey] ||
      closedSet[currentKey] ||
      (() => {
        const [x, y] = currentKey.split(",").map(Number);
        return { x, y };
      })();

    path.push(node);
    currentKey = cameFrom[currentKey];
  }

  return path;
}

function findRoute(start, goal, grid) {
  const openSet = {};
  const closedSet = {};
  const cameFrom = {};
  const gScore = {};
  const fScore = {};

  const startKey = toKey(start);
  let iterations = 0;

  openSet[startKey] = start;
  gScore[startKey] = 0;
  fScore[startKey] = heuristicDistance(start, goal);

  while (Object.keys(openSet).length > 0 && iterations < config.maxIterations) {
    iterations++;

    let currentKey = null;
    let lowestFScore = Infinity;

    for (const key in openSet) {
      if (fScore[key] < lowestFScore) {
        lowestFScore = fScore[key];
        currentKey = key;
      }
    }

    const current = openSet[currentKey];

    if (current.x === goal.x && current.y === goal.y) {
      return {
        path: reconstructPath(cameFrom, closedSet, openSet, currentKey),
        cost: gScore[currentKey],
        iterations
      };
    }

    delete openSet[currentKey];
    closedSet[currentKey] = current;

    const neighbors = getWalkableNeighbors(current, grid);

    for (const neighbor of neighbors) {
      const neighborKey = toKey(neighbor);

      if (closedSet[neighborKey]) {
        continue;
      }

      const tentativeGScore = gScore[currentKey] + neighbor.moveCost;

      if (
        gScore[neighborKey] === undefined ||
        tentativeGScore < gScore[neighborKey]
      ) {
        cameFrom[neighborKey] = currentKey;
        gScore[neighborKey] = tentativeGScore;
        fScore[neighborKey] = tentativeGScore + heuristicDistance(neighbor, goal);
        openSet[neighborKey] = neighbor;
      }
    }
  }

  return {
    path: [],
    cost: Infinity,
    iterations
  };
}

const result = findRoute(start, goal, grid);

console.log(
  "Path length:",
  result.path.length,
  "Cost:",
  result.cost,
  "Iterations:",
  result.iterations
);
```

### Notes on behavior
This matches the original logic closely:

- The grid is randomly filled with obstacles using a probability value.
- Start and goal are forcibly cleared.
- A\* uses:
  - `gScore` = traveled cost so far
  - `fScore` = `gScore + heuristic`
- Movement includes diagonals.
- Straight moves cost `1`, diagonal moves cost `1.414`.
- If no route is found before `maxIterations`, it returns:
  - empty path
  - `Infinity` cost
  - iteration count

